const j = $input.first().json;

// Gmail uses capitalized headers (Subject, From), Webhook uses lowercase
const subject = j.Subject ?? j.subject ?? j.body?.subject ?? '';
const from = j.From ?? j.from ?? j.body?.from ?? '';

// Try to get full email body from multiple possible locations
let emailBody = j.text ?? j.body?.text ?? '';

// Gmail: try to decode text/plain from payload parts
if (!emailBody && j.payload?.parts) {
  const findTextPart = (parts) => {
    for (const part of parts) {
      if (part.mimeType === 'text/plain' && part.body?.data) return part.body.data;
      if (part.parts) { const found = findTextPart(part.parts); if (found) return found; }
    }
    return null;
  };
  const b64 = findTextPart(j.payload.parts);
  if (b64) {
    try { emailBody = Buffer.from(b64, 'base64url').toString('utf-8'); } catch(e) {}
  }
}

// Gmail: fallback to snippet (short preview ~200 chars)
if (!emailBody) emailBody = j.snippet ?? '';

// Parse internalDate (Unix ms timestamp) to DD.MM.YYYY
let date = j.date ?? j.body?.date ?? '';
if (!date && j.internalDate) {
  const d = new Date(parseInt(j.internalDate));
  date = `${String(d.getDate()).padStart(2,'0')}.${String(d.getMonth()+1).padStart(2,'0')}.${d.getFullYear()}`;
}
if (!date) date = new Date().toISOString();

// Remove 'text' so Extract from File can safely use it for PDF content
const out = { ...j };
delete out.text;
out._email_subject = subject;
out._email_from = from;
out._email_body = emailBody;
out._email_date = date;

return [{ json: out }];

// Get email fields directly from 'E-Mail Text sichern' (bypasses PDF error)
const emailData = $("E-Mail Text sichern").first().json;

// Get PDF text only if extraction succeeded (no error in input)
const j = $input.first().json;
const pdfText = (!j.error && j.text) ? j.text : '';

const sep = '\n\n--- PDF Anhang ---\n';
const body = emailData._email_body ?? '';
const fullText = body + (pdfText ? sep + pdfText : '');

return [{ json: {
  subject: emailData._email_subject ?? '',
  from: emailData._email_from ?? '',
  text: fullText,
  date: emailData._email_date ?? new Date().toISOString(),
  has_pdf: !!pdfText
}}];

const raw = $input.first().json.output;
let cleaned = raw;
if (raw.includes('```')) {
  cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '');
}
const result = JSON.parse(cleaned.trim());
return [{ json: { ...result, original_email: $('E-Mail + PDF aufbereiten').first().json } }];

const raw = $input.first().json.output;
let cleaned = raw;
if (raw.includes('```')) {
  cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '');
}
const data = JSON.parse(cleaned.trim());
return [{ json: data }];

const d = $input.first().json;

const hexToRgb = (hex) => ({
  red:   parseInt(hex.slice(1,3), 16) / 255,
  green: parseInt(hex.slice(3,5), 16) / 255,
  blue:  parseInt(hex.slice(5,7), 16) / 255
});

const COLORS = {
  "Textilien":       hexToRgb("#1ED6A8"),
  "Werbematerial":   hexToRgb("#F5A623"),
  "Geschenkartikel": hexToRgb("#FF4D6D")
};

const color = COLORS[d.kategorie] || { red: 1, green: 1, blue: 1 };
const cell = (val) => ({ userEnteredValue: { stringValue: String(val ?? '') } });
const coloredCell = (val, c) => ({
  userEnteredValue: { stringValue: String(val ?? '') },
  userEnteredFormat: { backgroundColor: c }
});

const payload = {
  requests: [{
    appendCells: {
      sheetId: 0,
      rows: [{ values: [
        cell(d.datum),
        cell(d.firma),
        cell(d.kontakt),
        cell(d.email_telefon),
        coloredCell(d.kategorie, color),
        cell(d.artikel),
        cell(d.menge),
        cell(d.deadline),
        cell(d.budget)
      ]}],
      fields: "userEnteredValue,userEnteredFormat.backgroundColor"
    }
  }]
};

return [{ json: payload }];
